# %% ../nbs/00_core.ipynb 5
class VowelOrder(Enum):
    """Traditional Geez vowel order system.
    
    Latin key mapping follows Keyman/GFF convention:
    - 'e' → 1st order (ግዕዝ) — the most common form
    - 5th order (ኃምስ) has no direct key — accessed via 'ie' shortcut (3rd + 'e')
    - 6th order (ሳድስ) is the default bare consonant output
    """
    GEEZ  = (0, "ግዕዝ", "e", "ä")      # Base form — typed with 'e'
    KAEB  = (1, "ካዕብ", "u", "u")      # Second order
    SALIS = (2, "ሣልስ", "i", "i")      # Third order  
    RABE  = (3, "ራብዕ", "a", "a")      # Fourth order
    HAMS  = (4, "ኃምስ",  "", "e")      # Fifth order — accessed via 'ie' (FifthOrderRule)
    SADES = (5, "ሳድስ",  "", "ə")      # Sixth order — default (bare consonant)
    SABE  = (6, "ሳብዕ", "o", "o")      # Seventh order
    
    def __init__(self, index, geez_name, latin_key, ipa):
        self.index     = index
        self.geez_name = geez_name
        self.latin_key = latin_key
        self.ipa       = ipa
    
    @classmethod
    def from_latin_key(cls, key: str) -> Optional['VowelOrder']:
        """Get vowel order from Latin key."""
        for vowel in cls:
            if vowel.latin_key == key:
                return vowel
        return None
    
    @classmethod
    def from_index(cls, index: int) -> Optional['VowelOrder']:
        """Get vowel order from index."""
        for vowel in cls:
            if vowel.index == index:
                return vowel
        return None

# %% ../nbs/00_core.ipynb 8
@dataclass
class CharacterFamily:
    """
    Represents a family of Geez characters with vowel variations.
    
    Characters list must have exactly 7 entries (one per vowel order).
    Entries may be None for families that lack certain forms (e.g., labiovelars).
    """
    base_key     : str                      # Latin key (e.g., 'h', 's', 'l')
    characters   : List[Optional[str]]      # 7 characters in vowel order (None if form doesn't exist)
    name         : str                      # Human readable name
    unicode_range: Tuple[int, int]          # Unicode start and end points
    
    def __post_init__(self):
        if len(self.characters) != 7:
            raise ValueError(f"Character family must have exactly 7 entries, got {len(self.characters)}")
    
    def get_character(self, vowel_order: VowelOrder) -> Optional[str]:
        """Get character for specific vowel order."""
        return self.characters[vowel_order.index]
    
    def get_character_by_index(self, index: int) -> Optional[str]:
        """Get character by vowel index (0-6)."""
        if 0 <= index < 7:
            return self.characters[index]
        return None
    
    def get_character_by_latin_key(self, vowel_key: str) -> Optional[str]:
        """Get character by Latin vowel key."""
        vowel_order = VowelOrder.from_latin_key(vowel_key)
        if vowel_order:
            return self.get_character(vowel_order)
        return None
    
    @property
    def sadis(self) -> Optional[str]:
        """Get the 6th order (sadis) form - the default output form."""
        return self.characters[5]
    
    @property
    def valid_characters(self) -> List[str]:
        """Get list of non-None characters in this family."""
        return [c for c in self.characters if c is not None]

