@dataclass
class MappingsConfig:
    """User-configurable key sequence → character family mappings.

    `sequence_to_family` maps every typing sequence to its target family base_key.
    Single-char entries (e.g. ``'h': 'h'``) drive ``ConsonantRule``.
    Multi-char entries (e.g. ``'sh': 'sh'``, ``'tss': 'tss'``) drive
    ``DigramSecondKeyRule``.

    Use `default()` for factory settings and `save()`/`load()` for persistence
    to ``~/.gzkeyboard/mappings.json``.
    """

    sequence_to_family: Dict[str, str]

    CONFIG_DIR : ClassVar[Path] = Path.home() / '.gzkeyboard'
    CONFIG_PATH: ClassVar[Path] = Path.home() / '.gzkeyboard' / 'mappings.json'

    @classmethod
    def default(cls) -> 'MappingsConfig':
        """Return the factory-default key sequence mappings."""
        return cls(sequence_to_family={
            # Single-key consonants (drive ConsonantRule)
            'h': 'h',  'l': 'l',  'm': 'm',  'r': 'r',
            's': 's',  'q': 'q',  'b': 'b',  'v': 'v',
            't': 't',  'n': 'n',  'k': 'k',  'w': 'w',
            'z': 'z',  'y': 'y',  'd': 'd',  'j': 'j',
            'g': 'g',  'f': 'f',  'p': 'p',  'x': 'x',
            # Multi-key sequences (drive DigramSecondKeyRule)
            'sh':  'sh',  'zh':  'zh',  'ts':  'ts',  'tss': 'tss',
            'gn':  'gn',  'ch':  'ch',  'hh':  'hh',  'qh':  'qh',
            'kh':  'kh',
            'tt':  'tt',  'chh': 'chh', 'pp':  'pp',
            'hw':  'hw',  'kw':  'kw',  'qw':  'qw',  'gw':  'gw',
        })

    def get_consonant_map(self) -> Dict[str, str]:
        """Return ``{key: family_base_key}`` for all single-character sequences."""
        return {seq: fam for seq, fam in self.sequence_to_family.items() if len(seq) == 1}

    def get_digram_map(self) -> Dict[Tuple[str, str], str]:
        """Derive the digram rule map from multi-char sequences.

        For a sequence ``'tss'``, splits as ``('ts', 's') → 'tss'``.
        For ``'sh'``, splits as ``('s', 'h') → 'sh'``.
        The prefix (all chars except last) is the context key in the rule.
        """
        digram: Dict[Tuple[str, str], str] = {}
        for seq, fam in self.sequence_to_family.items():
            if len(seq) > 1:
                prefix, last = seq[:-1], seq[-1]
                digram[(prefix, last)] = fam
        return digram

    def get_pending_keys(self) -> Set[str]:
        """Return keys that produce no output (first char of digrams with no solo family).

        E.g. ``'c'`` starts ``'ch'``/``'chh'`` but has no single-char entry → pending.
        """
        single_keys  = {seq       for seq in self.sequence_to_family if len(seq) == 1}
        multi_starts = {seq[0]    for seq in self.sequence_to_family if len(seq) > 1}
        return multi_starts - single_keys

    def save(self, path: Optional[Path] = None):
        """Save mappings to JSON (default: ``~/.gzkeyboard/mappings.json``)."""
        target = path or self.CONFIG_PATH
        target.parent.mkdir(parents=True, exist_ok=True)
        with open(target, 'w', encoding='utf-8') as f:
            json.dump(self.sequence_to_family, f, ensure_ascii=False, indent=2)

    @classmethod
    def load(cls, path: Optional[Path] = None) -> 'MappingsConfig':
        """Load mappings from JSON, falling back to defaults if file not found."""
        target = path or cls.CONFIG_PATH
        if not target.exists():
            return cls.default()
        with open(target, 'r', encoding='utf-8') as f:
            data = json.load(f)
        return cls(sequence_to_family=data)

# %% ../nbs/00_core.ipynb 17
def explore_family(store: CharacterStore, base_key: str):
    """Display detailed information about a character family."""
    family = store.get_family(base_key)
    if not family:
        print(f"No family found for key '{base_key}'")
        return
    
    print(f"\n{family.name}")
    print("=" * len(family.name))
    print(f"Base key: {family.base_key}")
    print(f"Unicode range: U+{family.unicode_range[0]:04X} - U+{family.unicode_range[1]:04X}")
    print("\nCharacters:")
    
    for i, char in enumerate(family.characters):
        vowel = VowelOrder.from_index(i)
        print(f"  {vowel.geez_name:4} ({vowel.latin_key:2}): {char} (U+{ord(char):04X})")

def show_composition_examples(store: CharacterStore, examples: List[Tuple[str, str]]):
    """Show examples of character composition."""
    print("\nComposition Examples:")
    print("====================")
    print(f"{'Input':10} {'Output':8} {'Unicode':10} {'Family':15}")
    print("-" * 50)
    
    for base_key, vowel_key in examples:
        char = store.get_character(base_key, vowel_key)
        if char:
            input_str = f"{base_key}{vowel_key}"
            unicode_str = f"U+{ord(char):04X}"
            family_name = store.get_family(base_key).name.split('(')[0].strip()
            print(f"{input_str:10} {char:8} {unicode_str:10} {family_name:15}")
        else:
            print(f"{base_key}{vowel_key:10} {'N/A':8} {'N/A':10} {'N/A':15}")

# %% ../nbs/00_core.ipynb 22
def save_character_store(store: CharacterStore, filepath: Path):
    """Save character store to JSON file."""
    data = {
        'families': {
            key: {
                'base_key': family.base_key,
                'characters': family.characters,
                'name': family.name,
                'unicode_range': family.unicode_range
            }
            for key, family in store.families.items()
        }
    }
    
    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def load_character_store(filepath: Path) -> CharacterStore:
    """Load character store from JSON file."""
    with open(filepath, 'r', encoding='utf-8') as f:
        data = json.load(f)
    
    store = CharacterStore()
    store.families.clear()  # Remove default families
    store._character_to_family.clear()
    
    for key, family_data in data['families'].items():
        family = CharacterFamily(
            base_key=family_data['base_key'],
            characters=family_data['characters'],
            name=family_data['name'],
            unicode_range=tuple(family_data['unicode_range'])
        )
        store.add_family(family)
    
    return store
